const s = $json?.data?.content?.description;
let phone = '';
if (typeof s === 'string') {
  try { phone = JSON.parse(s)?.phone || JSON.parse(s)?.caption || ''; } catch {}
}
if (!phone) {
  const m = String(s||'').match(/(\+?84|0)\D*\d{9,10}/);
  phone = m ? m[0] : '';
}
phone = phone.replace(/[^\d+]/g,'').replace(/^\+84/,'0');
return { json: { phone } };

// Input: nhiều item có các field như: warranty_receipt, name, link_folder, link_image, link_images[], link, links_line, ...
// Output: mỗi warranty_receipt -> 1 item, giữ nguyên field của bản ghi đầu tiên, thêm:
//   - link_images: mảng link đã gom
//   - link_image_join: chuỗi "link1,link2,..."
//   - count: số link

const rows = $input.all().map((it,i)=>({
  json: it.json,
  i,
  row_number: Number(String(it.json.row_number ?? i).replace(/[^\d.-]/g,'')) || i,
})).sort((a,b)=>a.row_number - b.row_number);

const norm = v => String(v ?? '').normalize('NFKC').trim();
const isUrl = s => /^https?:\/\//i.test(String(s||'').trim());

const groups = new Map(); // key = warranty_receipt

for (const {json} of rows) {
  const key = norm(json.warranty_receipt ?? json.waranty_receipt ?? json.receipt ?? json.biennhan);
  if (!key) continue;

  if (!groups.has(key)) {
    // giữ NGUYÊN mọi field của bản ghi đầu tiên
    groups.set(key, { base: { ...json }, links: [], seen: new Set() });
  }
  const g = groups.get(key);

  // thu thập mọi nguồn link có thể
  const candidates = [];
  if (Array.isArray(json.link_images)) candidates.push(...json.link_images);
  if (json.link_image) candidates.push(json.link_image);
  if (json.link) candidates.push(json.link);
  if (typeof json.links_line === 'string') candidates.push(...json.links_line.split(/[,\s]+/));

  // dedupe + giữ thứ tự
  for (const c of candidates) {
    const s = String(c ?? '').trim();
    if (isUrl(s) && !g.seen.has(s)) {
      g.seen.add(s);
      g.links.push(s);
    }
  }
}

// xuất mỗi nhóm 1 item; giữ nguyên field đầu vào khác
return [...groups.values()].map(({base, links}) => {
  const out = { ...base };
  out.link_images = links;
  out.link_image_join = links.join(',');
  out.count = links.length;
  return { json: out };
});

// Input: { links_line: "https://a.jpg, https://b.png, ..."}
const raw = $input.first().json.link_image_join || '';
const split = raw
  .split(/[,\s]+/)           // phẩy, xuống dòng, khoảng trắng
  .map(s => s.trim())
  .filter(Boolean);

// Loại trùng, giữ thứ tự
const urls = [...new Set(split)];

// Trả về mỗi item 1 URL
return urls.map((u, i) => ({ json: { url: u, idx: i }}));

